# Pinocchio Vault Smart Contract

## Smart Contract Implementation

### Solidity Contract: `PinocchioVault.sol`

```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.18;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/math/SafeMath.sol";

contract PinocchioVault is ReentrancyGuard {
    using SafeMath for uint256;

    address public owner;
    mapping(address => uint256) private balances;

    event Deposit(address indexed user, uint256 amount);
    event Withdrawal(address indexed user, uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == owner, "Only the owner can execute this");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function deposit() external payable nonReentrant {
        require(msg.value > 0, "Deposit amount must be greater than 0");

        // Update balance
        balances[msg.sender] = balances[msg.sender].add(msg.value);

        emit Deposit(msg.sender, msg.value);
    }

    function withdraw(uint256 _amount) external nonReentrant {
        require(_amount > 0, "Withdrawal amount must be greater than 0");
        require(balances[msg.sender] >= _amount, "Insufficient balance");

        // Update balance
        balances[msg.sender] = balances[msg.sender].sub(_amount);

        // Interaction
        (bool success, ) = msg.sender.call{value: _amount}("");
        require(success, "Transfer failed");

        emit Withdrawal(msg.sender, _amount);
    }

    function getBalance(address _user) external view returns (uint256) {
        return balances[_user];
    }

    // Fallback functions to accept Ether
    receive() external payable {}

    fallback() external payable {}
}
```

### Key Security Measures

- **Reentrancy Guard**: Utilizes OpenZeppelin's `ReentrancyGuard` to prevent reentrancy attacks during deposit and withdrawal operations.
- **Checks-Effects-Interactions Pattern**: Ensure the state is modified before making any external calls to minimize reentrancy risks.
- **SafeMath Library**: Employs `SafeMath` for arithmetic operations to prevent overflow/underflow vulnerabilities.

### Gas Optimization

- Using `msg.sender.call` with proper gas considerations to limit potential gas overdrafts, optimizing transaction costs.
- Consolidated state updates to minimize storage operations.

## Security Analysis

### Potential Vulnerabilities and Mitigations

1. **Reentrancy Attack**:
   - Mitigation: `nonReentrant` modifier obtained from OpenZeppelin to protect the withdrawal function by preventing recursive function calls.

2. **Arithmetic Over/Underflow**:
   - Mitigation: SafeMath is employed for safe arithmetic operations to inherently handle overflows and underflows.

3. **Gas Limit & Refund**:
   - Mitigation: Use `.call{value: _amount}("")` instead of `.transfer` or `.send` methods as they might lead to the gas stipend issue.

4. **Fallback Function Misuse**:
   - Mitigation: Implementing a fallback function to ensure the contract doesn't accidentally reject Ether sent to it.

## Development Tests

### Test Cases: `PinocchioVault.test.js`

```javascript
const { expect } = require("chai");
const { ethers } = require("hardhat");

describe("PinocchioVault", function () {
  let PinocchioVault, pinocchioVault, owner, addr1;

  beforeEach(async function () {
    [owner, addr1] = await ethers.getSigners();
    PinocchioVault = await ethers.getContractFactory("PinocchioVault");
    pinocchioVault = await PinocchioVault.deploy();
    await pinocchioVault.deployed();
  });

  describe("Deposit and Withdraw", function () {
    it("Should allow users to deposit ether", async function () {
      await pinocchioVault.connect(addr1).deposit({ value: ethers.utils.parseEther("1") });
      expect(await pinocchioVault.getBalance(addr1.address)).to.equal(ethers.utils.parseEther("1"));
    });

    it("Should allow users to withdraw their ether", async function () {
      await pinocchioVault.connect(addr1).deposit({ value: ethers.utils.parseEther("1") });
      await pinocchioVault.connect(addr1).withdraw(ethers.utils.parseEther("1"));
      expect(await pinocchioVault.getBalance(addr1.address)).to.equal(0);
    });

    it("Should not allow withdrawals exceeding balance", async function () {
      await pinocchioVault.connect(addr1).deposit({ value: ethers.utils.parseEther("1") });
      await expect(pinocchioVault.connect(addr1).withdraw(ethers.utils.parseEther("2"))).to.be.revertedWith("Insufficient balance");
    });

    it("Should emit Deposit and Withdrawal events", async function () {
      await expect(pinocchioVault.connect(addr1).deposit({ value: ethers.utils.parseEther("1") }))
        .to.emit(pinocchioVault, "Deposit")
        .withArgs(addr1.address, ethers.utils.parseEther("1"));

      await expect(pinocchioVault.connect(addr1).withdraw(ethers.utils.parseEther("1")))
        .to.emit(pinocchioVault, "Withdrawal")
        .withArgs(addr1.address, ethers.utils.parseEther("1"));
    });
  });
});
```

